// // This module controls the fan speed based on temperature levels. It reads the temperature input and outputs the corresponding fan speed. The fan speed is determined as follows:
// - If the temperature is less than 20 degrees Celsius, the fan speed is 3 (high).
// - If the temperature is between 20 and 25 degrees Celsius, the fan speed is 2 (medium).
// - If the temperature is between 26 and 30 degrees Celsius, the fan speed is 1 (low).
// - If the temperature is greater than 30 degrees Celsius, the fan speed is 0 (off).
module fan_speed_controller (
    input clk,
    input reset,
    input [7:0] temperature, // 0 to 255, assuming temperature in degrees Celsius
    output reg [1:0] fan_speed // 0: off, 1: low, 2: medium, 3: high
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            fan_speed <= 0;
        end else begin
            if (temperature < 20) begin
                fan_speed <= 0;
            end else if (temperature <= 25) begin
                fan_speed <= 1;
            end else if (temperature <= 30) begin
                fan_speed <= 2;
            end else begin
                fan_speed <= 3;
            end
        end
    end
endmodule

